-- ============================================================
-- seed-production-data-local.sql
-- Datos de producción adaptados para entorno local Docker.
-- Excluye: app_settings, telegram_authorized_chats, telegram_usage
--   (tablas que no existen en el schema local)
-- ============================================================

SET session_replication_role = replica;
-- Limpiar datos existentes antes de insertar
TRUNCATE public.warehouse_stock, public.warehouse_movements, public.stock_movements,
  public.order_item_flavors, public.order_items, public.orders,
  public.branch_stock, public.branch_prices, public.recipes,
  public.promotion_rules, public.promotions, public.profiles,
  public.product_variants, public.products, public.variant_types,
  public.ingredients, public.branches
  RESTART IDENTITY CASCADE;

-- Nota: aplicar migración 016 desde Studio antes de correr este seed
-- ALTER TABLE branch_stock requiere ejecutarse como supabase_admin




















SET session_replication_role = DEFAULT;
